      <!-- header -->
      <div class="row pt-2">
        <div class="col-7 text-left">
          <h3>
            <b>Appointments</b>
          </h3>
        </div>
      </div>
      <div class="row mb-2 briefing text-left">
        <div class="col">You have {{ Appts.length || 0 }} upcoming appointment(s)</div>
