<script>
import AppointmentTile from "@/components/AppointmentTile";
import { mapState } from "vuex";
import http from "@/network/Base.js";

export default {
  name: "appointments",
  components: {
    AppointmentTile
  },
  data() {
    return {
      apptFilter: "All",
      allAppts: [],
      loading: false,
      modalShow: false,
      apptSelect: {},
      Appts: [
        {
          sz_bookedtime: 1592533150,
          sz_bookingtype: "virtual-care",
          sz_docname: "Dadson",
          sz_paymentmethod: "mobile-money"
        },
        {
          sz_bookedtime: 1593019150,
          sz_bookingtype: "virtual-care",
          sz_docname: "Ashong",
          sz_paymentmethod: "mobile-money"
        }
      ]
    };
  },
  watch: {
    apptFilter(val) {}
  },

  methods: {
    clearAllExpiredAppts() {},
    goBack() {
      this.$router.go(-1);
    },
    selectAppt(appt) {
      this.apptSelect = appt;
      // this.modalShow = true
      console.log(appt);
    },
    getAppoint(bookingstatus) {
      this.apptFilter = bookingstatus;

      if (bookingstatus == "All") {
        bookingstatus = " ";
      } else {
        this.apptFilter = bookingstatus;
      }
      this.loading = true;
      http()
        .get(
          `/patients/appointments?sz_bookingstatus=${bookingstatus}&sz_bookedforid=${this.userInfo.sz_userid}`
        )
        .then(({ data }) => {
          this.allAppts = data;
        })
        .catch(error => {
          this.loading = false;
          // console.log(error)
          // this.$snotify.error('Sorry, cannot get Service detail')
        })
        .finally(() => {
          this.loading = false;
        });
    }
  },
  created() {
    this.getAppoint("All");
  },
  computed: {
    ...mapState({
      userInfo: state => state.authStore.userInfo
    })
  }
};
</script>

