        />
      </fieldset>
      <fieldset>
        <select
          cf-conditional-consent="Yes"
          cf-questions="Select a day for your test. Holiday and weekend times may vary, call 0209404046 to confirm if you're booking on a weekend or holiday."
          name="appointmentdate"
          id="appointmentdate"
